import{_ as e,o as r,c as o,ag as a}from"./chunks/framework.6MCaaFDc.js";const p=JSON.parse('{"title":"Network Hardware","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/network-hardware.md","filePath":"theory/networks/network-hardware.md"}'),s={name:"theory/networks/network-hardware.md"};function i(n,t,d,l,c,h){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="network-hardware" tabindex="-1">Network Hardware <a class="header-anchor" href="#network-hardware" aria-label="Permalink to &quot;Network Hardware&quot;">​</a></h1><p>Every network needs physical components to make communication possible. From the cable in the wall to the router blinking in your lounge, each piece of hardware plays a specific role in getting data from one device to another.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Network hardware is primarily a Grade 11 topic. Understanding the role and function of each device is essential for Paper 2.</p></div><hr><h2 id="overview-of-network-hardware" tabindex="-1">Overview of Network Hardware <a class="header-anchor" href="#overview-of-network-hardware" aria-label="Permalink to &quot;Overview of Network Hardware&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Device</th><th>Purpose</th><th>Layer</th></tr></thead><tbody><tr><td><strong>NIC</strong></td><td>Connects device to network</td><td>Physical</td></tr><tr><td><strong>Hub</strong></td><td>Broadcasts data to all ports</td><td>Physical</td></tr><tr><td><strong>Switch</strong></td><td>Sends data to correct device only</td><td>Data Link</td></tr><tr><td><strong>Router</strong></td><td>Connects different networks; routes data</td><td>Network</td></tr><tr><td><strong>Modem</strong></td><td>Converts digital ↔ analogue signals</td><td>Physical</td></tr><tr><td><strong>WAP</strong></td><td>Provides wireless access to a LAN</td><td>Data Link</td></tr><tr><td><strong>Repeater</strong></td><td>Amplifies signal over long distances</td><td>Physical</td></tr><tr><td><strong>Bridge</strong></td><td>Connects two network segments</td><td>Data Link</td></tr><tr><td><strong>Firewall</strong></td><td>Filters traffic based on security rules</td><td>Network</td></tr></tbody></table><hr><h2 id="nic-—-network-interface-card" tabindex="-1">NIC — Network Interface Card <a class="header-anchor" href="#nic-—-network-interface-card" aria-label="Permalink to &quot;NIC — Network Interface Card&quot;">​</a></h2><p>A <strong>NIC</strong> (Network Interface Card) is the hardware component that physically connects a device to a network.</p><ul><li>Every networked device has a NIC (built-in or expansion card)</li><li>Assigned a unique <strong>MAC address</strong> (Media Access Control) — 48-bit hardware address</li><li>Can be wired (Ethernet port) or wireless (Wi-Fi)</li><li>Operates at 100 Mbps, 1 Gbps, or 10 Gbps depending on standard</li></ul><p><strong>MAC address format:</strong> <code>00:1A:2B:3C:4D:5E</code> (6 pairs of hexadecimal digits)</p><hr><h2 id="hub" tabindex="-1">Hub <a class="header-anchor" href="#hub" aria-label="Permalink to &quot;Hub&quot;">​</a></h2><p>A <strong>hub</strong> is a basic network device that connects multiple devices in a LAN.</p><p><strong>How it works:</strong></p><ul><li>Receives data on one port</li><li>Broadcasts it to <strong>all</strong> other ports</li><li>All devices receive every packet (even if not addressed to them)</li></ul><p><strong>Problems:</strong></p><ul><li>Creates unnecessary network traffic (<strong>collisions</strong>)</li><li>Security risk — all devices see all data</li><li>Largely replaced by switches</li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">Hubs are obsolete</p><p>Hubs are rarely used in modern networks. Switches are far more efficient. You may still see hubs in exam questions — know that they broadcast to all ports.</p></div><hr><h2 id="switch" tabindex="-1">Switch <a class="header-anchor" href="#switch" aria-label="Permalink to &quot;Switch&quot;">​</a></h2><p>A <strong>switch</strong> is an intelligent network device that connects multiple devices and sends data <strong>only to the intended recipient</strong>.</p><p><strong>How it works:</strong></p><ul><li>Maintains a <strong>MAC address table</strong> — maps port numbers to MAC addresses</li><li>When a frame arrives, it checks the destination MAC and sends it to the correct port only</li><li>Reduces collisions, improves efficiency</li></ul><p><strong>Types:</strong></p><ul><li><strong>Unmanaged switch</strong> — plug and play, no configuration</li><li><strong>Managed switch</strong> — configurable (VLANs, QoS, monitoring)</li></ul><table tabindex="0"><thead><tr><th>Hub vs Switch</th><th>Hub</th><th>Switch</th></tr></thead><tbody><tr><td>Data delivery</td><td>Broadcast to all ports</td><td>Only to destination port</td></tr><tr><td>Collisions</td><td>Many</td><td>Minimal</td></tr><tr><td>Security</td><td>Low</td><td>Better</td></tr><tr><td>Speed</td><td>Shared</td><td>Dedicated per connection</td></tr><tr><td>Used today</td><td>Rarely</td><td>Universally</td></tr></tbody></table><hr><h2 id="router" tabindex="-1">Router <a class="header-anchor" href="#router" aria-label="Permalink to &quot;Router&quot;">​</a></h2><p>A <strong>router</strong> connects different networks together and <strong>routes data packets</strong> between them using IP addresses.</p><p><strong>Functions:</strong></p><ul><li>Connects your LAN to the internet (WAN)</li><li>Assigns IP addresses via DHCP</li><li>Acts as a gateway between networks</li><li>Provides NAT (Network Address Translation) — one public IP for many devices</li><li>Most home routers include a built-in switch and WAP</li></ul><p><strong>Routing process:</strong></p><ol><li>Packet arrives at router with destination IP address</li><li>Router checks its <strong>routing table</strong></li><li>Forwards packet to the next hop toward the destination</li><li>Process repeats until packet reaches destination</li></ol><p><strong>Home router vs Enterprise router:</strong></p><ul><li>Home router: simple, consumer-grade, all-in-one (router + switch + WAP + modem)</li><li>Enterprise router: high-performance, complex routing protocols, handles thousands of connections</li></ul><hr><h2 id="modem" tabindex="-1">Modem <a class="header-anchor" href="#modem" aria-label="Permalink to &quot;Modem&quot;">​</a></h2><p>A <strong>modem</strong> (MOdulator-DEModulator) converts signals between digital (computer format) and analogue (telephone line format).</p><p><strong>Why needed:</strong></p><ul><li>Phone lines and cable TV lines carry analogue signals</li><li>Computers use digital signals</li><li>Modem converts digital → analogue for sending; analogue → digital for receiving</li></ul><p><strong>Types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Technology</th><th>Speed</th></tr></thead><tbody><tr><td>ADSL modem</td><td>Phone line</td><td>Up to 24 Mbps</td></tr><tr><td>Cable modem</td><td>Coaxial (TV cable)</td><td>Up to 1 Gbps</td></tr><tr><td>Fibre ONT</td><td>Fibre optic</td><td>Up to 1 Gbps+</td></tr><tr><td>4G/LTE modem</td><td>Mobile network</td><td>Up to 150 Mbps</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Most home devices are a modem + router + switch + WAP combined</p><p>ISPs provide a single unit that does all four jobs. The term &quot;modem&quot; is commonly used even when the device is technically a &quot;residential gateway.&quot;</p></div><hr><h2 id="wap-—-wireless-access-point" tabindex="-1">WAP — Wireless Access Point <a class="header-anchor" href="#wap-—-wireless-access-point" aria-label="Permalink to &quot;WAP — Wireless Access Point&quot;">​</a></h2><p>A <strong>WAP</strong> (Wireless Access Point) connects wireless devices to a wired LAN.</p><ul><li>Transmits and receives Wi-Fi signals (IEEE 802.11)</li><li>Connected to the switch/router via Ethernet cable</li><li>Extends the reach of a LAN wirelessly</li><li>Each WAP has an <strong>SSID</strong> (Service Set Identifier) — the visible Wi-Fi network name</li></ul><p><strong>WAP vs Router:</strong></p><ul><li>A WAP only provides wireless connectivity — it does not route between networks</li><li>A router can include a WAP, but they are separate functions</li></ul><p><strong>Enterprise WAPs:</strong></p><ul><li>Ceiling-mounted, manage dozens of simultaneous connections</li><li>Managed centrally by a <strong>wireless LAN controller</strong></li><li>Used in schools, hospitals, shopping centres</li></ul><hr><h2 id="repeater" tabindex="-1">Repeater <a class="header-anchor" href="#repeater" aria-label="Permalink to &quot;Repeater&quot;">​</a></h2><p>A <strong>repeater</strong> amplifies and regenerates a network signal to extend its range.</p><ul><li>Signals weaken over long cable runs (attenuation)</li><li>A repeater boosts the signal so it can travel further</li><li>Does not filter or manage traffic — purely amplifies</li><li>Wireless repeaters extend Wi-Fi range (also called &quot;Wi-Fi extenders&quot; or &quot;range extenders&quot;)</li></ul><hr><h2 id="firewall" tabindex="-1">Firewall <a class="header-anchor" href="#firewall" aria-label="Permalink to &quot;Firewall&quot;">​</a></h2><p>A <strong>firewall</strong> is a security device (hardware or software) that monitors and controls incoming and outgoing network traffic based on predefined security rules.</p><p><strong>What it does:</strong></p><ul><li>Blocks unauthorised access to the network</li><li>Allows legitimate traffic through</li><li>Can filter by IP address, port number, protocol</li></ul><p><strong>Types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Software firewall</td><td>Installed on a device (Windows Defender Firewall)</td></tr><tr><td>Hardware firewall</td><td>Dedicated device between network and internet</td></tr><tr><td>Packet filtering</td><td>Checks source/destination IP and port</td></tr><tr><td>Stateful inspection</td><td>Tracks connection state; smarter filtering</td></tr></tbody></table><hr><h2 id="cables-and-connectors" tabindex="-1">Cables and Connectors <a class="header-anchor" href="#cables-and-connectors" aria-label="Permalink to &quot;Cables and Connectors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cable Type</th><th>Description</th><th>Max Speed</th><th>Max Distance</th></tr></thead><tbody><tr><td><strong>Cat5e</strong> (UTP)</td><td>Twisted-pair copper</td><td>1 Gbps</td><td>100 m</td></tr><tr><td><strong>Cat6</strong> (UTP)</td><td>Twisted-pair copper</td><td>10 Gbps</td><td>55 m</td></tr><tr><td><strong>Cat6a</strong> (UTP)</td><td>Twisted-pair copper</td><td>10 Gbps</td><td>100 m</td></tr><tr><td><strong>Coaxial</strong></td><td>Thick copper with shielding</td><td>Varies</td><td>500 m</td></tr><tr><td><strong>Fibre optic</strong></td><td>Light through glass/plastic</td><td>Up to Tbps</td><td>Kilometres</td></tr></tbody></table><p><strong>RJ-45 connector</strong> — standard plug for Ethernet cables (looks like a large phone plug)</p><p><strong>Fibre optic advantages:</strong></p><ul><li>Much faster — light travels faster than electrical signals</li><li>Not affected by electromagnetic interference (EMI)</li><li>More secure — cannot be easily tapped</li><li>Higher cost, more fragile</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>NIC</strong></td><td>Network Interface Card — hardware connecting device to network</td></tr><tr><td><strong>MAC address</strong></td><td>Unique hardware address of a NIC (48-bit hex)</td></tr><tr><td><strong>Hub</strong></td><td>Network device that broadcasts to all ports</td></tr><tr><td><strong>Switch</strong></td><td>Network device that sends data only to the destination port</td></tr><tr><td><strong>Router</strong></td><td>Connects networks; routes packets using IP addresses</td></tr><tr><td><strong>Modem</strong></td><td>Converts digital ↔ analogue signals for transmission</td></tr><tr><td><strong>WAP</strong></td><td>Wireless Access Point — provides Wi-Fi access to a LAN</td></tr><tr><td><strong>Firewall</strong></td><td>Security device filtering network traffic</td></tr><tr><td><strong>SSID</strong></td><td>Wi-Fi network name broadcast by a WAP</td></tr><tr><td><strong>Repeater</strong></td><td>Amplifies network signal to extend range</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between a hub and a switch?&quot;</strong> — Hub broadcasts to all ports (collisions, less efficient); switch sends only to the correct device using MAC address table (more efficient, more secure)</p></li><li><p><strong>&quot;What is the function of a router?&quot;</strong> — Routes data packets between different networks; connects LAN to internet; assigns IP addresses via DHCP</p></li><li><p><strong>&quot;What is a MAC address? Where is it stored?&quot;</strong> — Unique 48-bit hardware address assigned to every NIC; stored on the NIC itself</p></li><li><p><strong>&quot;What is the purpose of a modem?&quot;</strong> — Converts digital signals from a computer to analogue signals for transmission over phone/cable lines, and vice versa</p></li><li><p><strong>&quot;Give ONE advantage of fibre optic cable over UTP cable&quot;</strong> — Much faster data transmission; not affected by electromagnetic interference; can transmit over much longer distances</p></li></ol></div>',75)])])}const u=e(s,[["render",i]]);export{p as __pageData,u as default};
